export function scoreExpansionCandidate(args: {
  candidate: EventCandidate;
  theme: InvestmentThemeDefinition;
  asset: UniverseAssetDefinition;
  inWatchlist: boolean;
  hasMarketData: boolean;
}): number {
  const aliasBoost = (args.asset.aliases || []).some((alias) => args.candidate.text.includes(normalize(alias))) ? 10 : 0;
  const commodityBoost = args.asset.commodity && args.theme.commodities.includes(args.asset.commodity) ? 5 : 0;
  const watchlistBoost = args.inWatchlist ? 8 : 0;
  const marketBoost = args.hasMarketData ? 6 : 0;
  const liquidityBoost = args.asset.liquidityTier === 'core' ? 8 : args.asset.liquidityTier === 'high' ? 5 : 2;
  return clamp(
    Math.round(
      36
      + args.candidate.credibility * 0.2
      + args.candidate.corroboration * 0.12
      + args.candidate.marketStress * 18
      + args.candidate.aftershockIntensity * 12
      + aliasBoost
      + commodityBoost
      + watchlistBoost
      + marketBoost
      + liquidityBoost,
    ),
    28,
    96,
  );
}

function findMatchingThemes(candidate: EventCandidate): InvestmentThemeDefinition[] {
  const themeCatalog = listEffectiveThemeCatalog();
  const matches = themeCatalog.filter((rule) => rule.triggers.some((trigger) => matchesThemeTrigger(candidate.text, trigger)));
  if (matches.length > 0) return matches;
  if (candidate.matchedSymbols.length > 0 && candidate.marketStress >= 0.55) {
    return themeCatalog.filter((rule) => candidate.matchedSymbols.some((symbol) => themeHasAssetSymbol(rule, symbol)));
  }
  return [];
}

function marketMoveMap(markets: MarketData[]): Map<string, MarketData> {
  const map = new Map<string, MarketData>();
  for (const market of markets) {
    if (market.symbol) map.set(market.symbol, market);
  }
  return map;
}

function dedupeThemeAssets(assets: ThemeAssetDefinition[]): ThemeAssetDefinition[] {
  const seen = new Set<string>();
  const output: ThemeAssetDefinition[] = [];
  for (const asset of assets) {
    const key = themeAssetKey(asset);
    if (seen.has(key)) continue;
    seen.add(key);
    output.push(asset);
  }
  return output;
}

function buildKnowledgeGraphMappingSupport(args: {
  theme: InvestmentThemeDefinition;
  candidate: EventCandidate;
  asset: UniverseAssetDefinition;
  graphSignalScore: number;
  transferEntropy: number;
  informationFlowScore: number;
  leadLagScore: number;
  replayUtility: number;
}): {
  supportScore: number;
  dominantRelationType: string;
} {
  return {
    supportScore: clamp(
      Math.round(
        args.graphSignalScore * 0.34
        + args.transferEntropy * 0.18
        + args.informationFlowScore * 0.26
        + args.leadLagScore * 0.12
        + args.replayUtility * 0.1,
      ),
      0,
      100,
    ),
    dominantRelationType: args.asset.commodity ? 'commodity-exposure' : `${args.asset.sector}-exposure`,
  };
}

function matchesThemeTrigger(text: string, trigger: string): boolean {
  const normalized = normalize(text);
  const normalizedTrigger = normalize(trigger);
  return normalized.includes(normalizedTrigger);
}

function themeHasAssetSymbol(rule: InvestmentThemeDefinition, symbol: string): boolean {
  return rule.assets.some((asset: ThemeAssetDefinition) => normalize(asset.symbol) === normalize(symbol));
}

export function buildCandidateExpansionReviews(args: {
  candidates: EventCandidate[];
  markets: MarketData[];
}): CandidateExpansionReview[] {
  const marketMap = marketMoveMap(args.markets);
  const watchlistLookup = buildWatchlistLookup();
  const nextReviews = new Map<string, CandidateExpansionReview>();

  for (const candidate of args.candidates) {
    const themes = findMatchingThemes(candidate);
    for (const theme of themes) {
      const effectiveAssets = new Set(getEffectiveThemeAssets(theme).map(themeAssetKey));
      const effectiveThemeAssets = getEffectiveThemeAssets(theme);
      const existingSectors = new Set(effectiveThemeAssets.map((item) => normalize(item.sector)));
      const existingKinds = new Set(effectiveThemeAssets.map((item) => item.assetKind));
      const existingCommodities = new Set(
        effectiveThemeAssets
          .map((item) => normalize(item.commodity || ''))
          .filter(Boolean),
      );
      const themeCatalog = UNIVERSE_ASSET_CATALOG.filter((asset) => asset.themeIds.includes(theme.id));

      for (const asset of themeCatalog) {
        if (effectiveAssets.has(themeAssetKey(asset))) continue;
        const reviewId = candidateReviewId(theme.id, asset.symbol, asset.direction, asset.role);
        const previous = candidateReviews.get(reviewId);
        const inWatchlist = watchlistLookup.has(normalize(asset.symbol));
        const hasMarketData = marketMap.has(asset.symbol);
        const knowledgeGraphSupport = buildKnowledgeGraphMappingSupport({
          theme,
          candidate,
          asset,
          graphSignalScore: clamp(candidate.corroborationQuality + candidate.sourceDiversity * 4, 0, 100),
          transferEntropy: 0,
          informationFlowScore: clamp(candidate.marketStress * 100, 0, 100),
          leadLagScore: clamp((candidate.aftershockIntensity - 0.25) * 100, -100, 100),
          replayUtility: Number(((candidate.marketStress + candidate.aftershockIntensity) * 20).toFixed(2)),
        });
        const coverageGainScore = clamp(
          Math.round(
            32
            + (existingSectors.has(normalize(asset.sector)) ? 0 : 24)
            + (existingKinds.has(asset.assetKind) ? 0 : 18)
            + (asset.commodity && !existingCommodities.has(normalize(asset.commodity)) ? 12 : 0)
            + (hasMarketData ? 6 : 0),
          ),
          12,
          100,
        );
        const replayUtilityGainScore = clamp(
          Math.round(
            20
            + candidate.marketStress * 18
            + candidate.aftershockIntensity * 16
            + candidate.corroborationQuality * 0.14
            + (hasMarketData ? 8 : 0)
            + (inWatchlist ? 4 : 0),
          ),
          12,
          100,
        );
        const confidence = clamp(
          Math.round(
            scoreExpansionCandidate({ candidate, theme, asset, inWatchlist, hasMarketData }) * 0.72
            + knowledgeGraphSupport.supportScore * 0.16
            + coverageGainScore * 0.08
            + replayUtilityGainScore * 0.04,
          ),
          24,
          98,
        );
        const supportingSignals = [
          candidate.title,
          `Theme=${theme.label}`,
          `Credibility=${candidate.credibility}`,
          `Corroboration=${candidate.corroboration}`,
          `Stress=${candidate.marketStress.toFixed(2)}`,
          `Aftershock=${candidate.aftershockIntensity.toFixed(2)}`,
          `KG=${knowledgeGraphSupport.supportScore.toFixed(0)} ${knowledgeGraphSupport.dominantRelationType}`,
          `CoverageGain=${coverageGainScore}`,
          `ReplayValue=${replayUtilityGainScore}`,
          ...(asset.aliases || []).filter((alias) => candidate.text.includes(normalize(alias))).map((alias) => `Alias=${alias}`),
          ...(inWatchlist ? ['User watchlist overlap'] : []),
          ...(hasMarketData ? ['Live market data available'] : ['No live market data yet']),
        ].slice(0, 7);

        const review: CandidateExpansionReview = {
          id: reviewId,
          themeId: theme.id,
          themeLabel: theme.label,
          symbol: asset.symbol,
          assetName: inWatchlist ? (watchlistLookup.get(normalize(asset.symbol))?.name || asset.name) : asset.name,
          assetKind: asset.assetKind,
          sector: asset.sector,
          commodity: asset.commodity || null,
          direction: asset.direction,
          role: asset.role,
          confidence,
          source: previous?.source || (inWatchlist ? 'watchlist' : 'heuristic'),
          status: previous?.status || 'open',
          reason: previous?.reason || `${asset.name} extends ${theme.label} coverage into ${asset.sector}${asset.commodity ? ` / ${asset.commodity}` : ''}.`,
          supportingSignals: previous?.supportingSignals?.length ? previous.supportingSignals.slice(0, 8) : supportingSignals,
          requiresMarketData: !hasMarketData,
          knowledgeGraphScore: Number(knowledgeGraphSupport.supportScore.toFixed(2)),
          coverageGainScore,
          replayUtilityGainScore,
          autoApproved: previous?.autoApproved || false,
          autoApprovalMode: previous?.autoApprovalMode || null,
          acceptedAt: previous?.acceptedAt || null,
          probationStatus: previous?.probationStatus || 'n/a',
          probationCycles: previous?.probationCycles || 0,
          probationHits: previous?.probationHits || 0,
          probationMisses: previous?.probationMisses || 0,
          lastUpdatedAt: nowIso(),
        };
        const existing = nextReviews.get(reviewId);
        if (!existing || existing.confidence < review.confidence) {
          nextReviews.set(reviewId, review);
        }
      }
    }
  }

  for (const existing of candidateReviews.values()) {
    if (!nextReviews.has(existing.id)) nextReviews.set(existing.id, existing);
  }

  return Array.from(nextReviews.values())
    .sort((a, b) => {
      const statusRank = (value: CandidateExpansionReview['status']): number => (value === 'open' ? 0 : value === 'accepted' ? 1 : 2);
      return statusRank(a.status) - statusRank(b.status)
        || b.confidence - a.confidence
        || Date.parse(b.lastUpdatedAt) - Date.parse(a.lastUpdatedAt);
    })
    .slice(0, MAX_CANDIDATE_REVIEWS);
}

function countAutoApprovedByTheme(reviews: CandidateExpansionReview[], themeId: string): number {
  return reviews.filter((review) => review.themeId === themeId && review.status === 'accepted' && review.autoApproved).length;
}

function countAcceptedByThemeSector(reviews: CandidateExpansionReview[], themeId: string, sector: string): number {
  return reviews.filter((review) =>
    review.themeId === themeId
    && review.status === 'accepted'
    && normalize(review.sector) === normalize(sector),
  ).length;
}

function countAcceptedByThemeAssetKind(reviews: CandidateExpansionReview[], themeId: string, assetKind: InvestmentAssetKind): number {
  return reviews.filter((review) =>
    review.themeId === themeId
    && review.status === 'accepted'
    && review.assetKind === assetKind,
  ).length;
}

function countAcceptedByThemeDirection(reviews: CandidateExpansionReview[], themeId: string, direction: InvestmentDirection): number {
  return reviews.filter((review) =>
    review.themeId === themeId
    && review.status === 'accepted'
    && review.direction === direction,
  ).length;
}

interface CandidateAutoApprovalAssessment {
  approved: boolean;
  score: number;
  reason: string;
}

function assessAutoApprovalReview(
  review: CandidateExpansionReview,
  policy: UniverseExpansionPolicy,
  allReviews: CandidateExpansionReview[],
): CandidateAutoApprovalAssessment {
  if (review.status !== 'open') return { approved: false, score: 0, reason: 'not-open' };
  if (policy.mode === 'manual') return { approved: false, score: 0, reason: 'manual-policy' };
  if (policy.requireMarketData && review.requiresMarketData) return { approved: false, score: 0, reason: 'market-data-required' };

  const themeApproved = countAutoApprovedByTheme(allReviews, review.themeId);
  if (themeApproved >= policy.maxAutoApprovalsPerTheme) {
    return { approved: false, score: 0, reason: 'theme-cap-reached' };
  }

  const acceptedInSector = countAcceptedByThemeSector(allReviews, review.themeId, review.sector);
  if (acceptedInSector >= policy.maxAutoApprovalsPerSectorPerTheme) {
    return { approved: false, score: 0, reason: 'sector-cap-reached' };
  }

  const acceptedInAssetKind = countAcceptedByThemeAssetKind(allReviews, review.themeId, review.assetKind);
  if (acceptedInAssetKind >= policy.maxAutoApprovalsPerAssetKindPerTheme) {
    return { approved: false, score: 0, reason: 'asset-kind-cap-reached' };
  }

  if (policy.mode === 'guarded-auto' && review.source === 'codex' && review.confidence < policy.minCodexConfidence) {
    return { approved: false, score: review.confidence, reason: 'codex-confidence-too-low' };
  }

  let score = review.confidence;
  const sourceBonus = review.source === 'codex'
    ? 10
    : review.source === 'market'
      ? 8
      : review.source === 'watchlist'
        ? 6
        : 2;
  const roleBonus = review.role === 'hedge' ? 7 : review.role === 'confirm' ? 4 : 1;
  const signalBonus = Math.min(12, review.supportingSignals.length * 2);
  const assetKindBonus = review.assetKind === 'etf' ? 5 : review.assetKind === 'commodity' || review.assetKind === 'fx' || review.assetKind === 'rate' ? 4 : 2;
  const commodityBonus = review.commodity ? 4 : 0;
  const knowledgeBonus = clamp(Math.round((Number(review.knowledgeGraphScore) || 0) * 0.12), 0, 12);
  const coverageBonus = clamp(Math.round((Number(review.coverageGainScore) || 0) * 0.08), 0, 10);
  const replayValueBonus = clamp(Math.round((Number(review.replayUtilityGainScore) || 0) * 0.06), 0, 8);
  const missingMarketPenalty = review.requiresMarketData ? 14 : 0;
  const sectorCrowdingPenalty = acceptedInSector * 12;
  const assetKindCrowdingPenalty = acceptedInAssetKind * 10;
  const directionCrowdingPenalty = countAcceptedByThemeDirection(allReviews, review.themeId, review.direction) * 4;
  const themeCrowdingPenalty = themeApproved * 5;
  score += sourceBonus + roleBonus + signalBonus + assetKindBonus + commodityBonus + knowledgeBonus + coverageBonus + replayValueBonus;
  score -= missingMarketPenalty + sectorCrowdingPenalty + assetKindCrowdingPenalty + directionCrowdingPenalty + themeCrowdingPenalty;
  score = clamp(Math.round(score), 0, 100);

  const threshold = policy.mode === 'full-auto'
    ? Math.max(52, policy.minAutoApproveScore - 12)
    : policy.minAutoApproveScore;
  const approved = score >= threshold;
  const reason = `score=${score} source=${review.source} role=${review.role} sectorFill=${acceptedInSector}/${policy.maxAutoApprovalsPerSectorPerTheme} kindFill=${acceptedInAssetKind}/${policy.maxAutoApprovalsPerAssetKindPerTheme}`;
  return { approved, score, reason };
}

export function applyUniverseExpansionPolicy(reviews: CandidateExpansionReview[], policy: UniverseExpansionPolicy): CandidateExpansionReview[] {
  const output = reviews.map((review) => ({ ...review }));
  for (let index = 0; index < output.length; index += 1) {
    const review = output[index]!;
    const assessment = assessAutoApprovalReview(review, policy, output);
    if (!assessment.approved) continue;
    const acceptedAt = nowIso();
    output[index] = {
      ...review,
      status: 'accepted',
      autoApproved: true,
      autoApprovalMode: policy.mode,
      acceptedAt,
      probationStatus: 'active',
      probationCycles: 0,
      probationHits: 0,
      probationMisses: 0,
      reason: `${review.reason} Auto-approved by ${policy.mode} policy (${assessment.reason}).`,
      lastUpdatedAt: acceptedAt,
    };
  }
  return output;
}

export function evaluateCandidateReviewProbation(args: {
  reviews: CandidateExpansionReview[];
  activeCandidates: EventCandidate[];
  mappings: DirectAssetMapping[];
  backtests: EventBacktestRow[];
  policy: UniverseExpansionPolicy;
}): CandidateExpansionReview[] {
  const activeThemeIds = new Set(args.activeCandidates.flatMap((candidate) => findMatchingThemes(candidate).map((theme) => theme.id)));
  return args.reviews.map((review) => {
    if (review.status !== 'accepted' || !review.autoApproved) return review;
    if (!activeThemeIds.has(review.themeId)) return review;

    const hasMapping = args.mappings.some((mapping) =>
      mapping.themeId === review.themeId
      && normalize(mapping.symbol) === normalize(review.symbol)
      && mapping.direction === review.direction,
    );
    const hasBacktest = args.backtests.some((row) =>
      row.themeId === review.themeId
      && normalize(row.symbol) === normalize(review.symbol)
      && row.direction === review.direction,
    );
    const hit = hasMapping || hasBacktest;
    const nextCycles = review.probationCycles + 1;
    const nextHits = review.probationHits + (hit ? 1 : 0);
    const nextMisses = review.probationMisses + (hit ? 0 : 1);
    const next: CandidateExpansionReview = {
      ...review,
      probationCycles: nextCycles,
      probationHits: nextHits,
      probationMisses: nextMisses,
      lastUpdatedAt: nowIso(),
    };

    if (!hit && nextMisses >= args.policy.autoDemoteMisses) {
      return {
        ...next,
        status: 'open',
        autoApproved: false,
        probationStatus: 'demoted',
        autoApprovalMode: review.autoApprovalMode || args.policy.mode,
        reason: `${review.reason} Auto-demoted after ${nextMisses} probation misses.`,
      };
    }
    if (hit && nextCycles >= args.policy.probationCycles) {
      return {
        ...next,
        probationStatus: 'graduated',
      };
    }
    return {
      ...next,
      probationStatus: 'active',
    };
  });
}

export function buildCoverageGaps(args: {
  candidates: EventCandidate[];
  reviews: CandidateExpansionReview[];
}): UniverseCoverageGap[] {
  const gaps = new Map<string, UniverseCoverageGap>();

  for (const candidate of args.candidates) {
    const themes = findMatchingThemes(candidate);
    for (const theme of themes) {
      const effectiveAssets = getEffectiveThemeAssets(theme);
      const effectiveKinds = new Set<InvestmentAssetKind>(effectiveAssets.map((asset) => asset.assetKind));
      const effectiveSectors = new Set<string>(effectiveAssets.map((asset) => asset.sector));
      const catalogAssets = UNIVERSE_ASSET_CATALOG.filter((asset) => asset.themeIds.includes(theme.id));
      const availableKinds = new Set<InvestmentAssetKind>([...theme.assets, ...catalogAssets].map((asset) => asset.assetKind));
      const availableSectors = new Set<string>([...theme.sectors, ...catalogAssets.map((asset) => asset.sector)]);
      const missingAssetKinds = Array.from(availableKinds).filter((kind) => !effectiveKinds.has(kind));
      const missingSectors = Array.from(availableSectors).filter((sector) => !effectiveSectors.has(sector));
      const suggestedSymbols = args.reviews
        .filter((review) => review.themeId === theme.id && review.status === 'open')
        .map((review) => review.symbol)
        .slice(0, 5);

      if (!missingAssetKinds.length && !missingSectors.length && effectiveAssets.length >= Math.min(3, theme.assets.length)) {
        continue;
      }

      const severity: UniverseCoverageGap['severity'] =
        effectiveAssets.length < 2 || missingAssetKinds.length >= 2 || missingSectors.length >= 2
          ? 'critical'
          : missingAssetKinds.length > 0 || missingSectors.length > 0
            ? 'elevated'
            : 'watch';

      gaps.set(`${theme.id}::${candidate.region}`, {
        id: `${theme.id}::${candidate.region}`,
        themeId: theme.id,
        themeLabel: theme.label,
        region: candidate.region,
        severity,
        reason: `${theme.label} lacks full cross-sector coverage for ${candidate.region}.`,
        missingAssetKinds,
        missingSectors,
        suggestedSymbols,
      });
    }
  }

  return Array.from(gaps.values())
    .sort((a, b) => {
      const severityRank = (value: UniverseCoverageGap['severity']): number => (value === 'critical' ? 0 : value === 'elevated' ? 1 : 2);
      return severityRank(a.severity) - severityRank(b.severity) || a.themeLabel.localeCompare(b.themeLabel);
    })
    .slice(0, 24);
}

export function buildUniverseCoverageSummary(args: {
  candidates: EventCandidate[];
  mappings: DirectAssetMapping[];
  reviews: CandidateExpansionReview[];
  gaps: UniverseCoverageGap[];
}): UniverseCoverageSummary {
  const activeThemeIds = Array.from(new Set(args.candidates.flatMap((candidate) => findMatchingThemes(candidate).map((theme) => theme.id))));
  const activeAssets = dedupeThemeAssets(activeThemeIds.flatMap((themeId) => {
    const theme = getThemeRule(themeId);
    return theme ? getEffectiveThemeAssets(theme) : [];
  }));

  return {
    totalCatalogAssets: UNIVERSE_ASSET_CATALOG.length,
    activeAssetKinds: Array.from(new Set(activeAssets.map((asset) => asset.assetKind))).sort(),
    activeSectors: Array.from(new Set(activeAssets.map((asset) => asset.sector))).sort(),
    directMappingCount: args.mappings.length,
    dynamicApprovedCount: args.reviews.filter((review) => review.status === 'accepted').length,
    openReviewCount: args.reviews.filter((review) => review.status === 'open').length,
    gapCount: args.gaps.length,
    uncoveredThemeCount: Array.from(new Set(args.gaps.map((gap) => gap.themeId))).length,
  };
}

import type {
  InvestmentThemeDefinition,
  EventCandidate,
  ThemeAssetDefinition,
  CandidateExpansionReview,
  ThemePolicyDefinition,
  ThemeClassification,
  NarrativeShadowState,
} from './types';
import { THEME_RULES, SPECIAL_SYMBOL_POLICY, UNIVERSE_ASSET_CATALOG } from './constants';
import { automatedThemes, candidateReviews, setAutomatedThemes } from './module-state';
import {
  normalize,
  matchesThemeTrigger,
  dedupeThemeAssets,
  clamp,
} from './utils';
import { getMarketWatchlistEntries } from '../market-watchlist';
import { getSignificantPatterns, type DiscoveredLink } from '../pattern-discovery';
import { scoreNarrativeShadowThemes } from './narrative-factor';

type ThemeRule = InvestmentThemeDefinition;
export interface ThemeMatchDetail {
  theme: ThemeRule;
  triggerHits: string[];
  triggerHitCount: number;
  narrativeAlignmentScore: number;
  narrativeShadowState: NarrativeShadowState;
  narrativeShadowPosterior: number;
  narrativeShadowDisagreement: number;
  narrativeShadowTopThemeId: string | null;
  score: number;
  matchedBy: 'trigger' | 'fallback-symbol';
}

/**
 * Convert a CandidateExpansionReview to a ThemeAssetDefinition
 */
function reviewToThemeAsset(review: CandidateExpansionReview): ThemeAssetDefinition {
  return {
    symbol: review.symbol,
    name: review.assetName,
    assetKind: review.assetKind,
    sector: review.sector,
    commodity: review.commodity || undefined,
    direction: review.direction,
    role: review.role,
  };
}

function normalizeThemePolicy(policy?: ThemePolicyDefinition): ThemePolicyDefinition | undefined {
  if (!policy) return undefined;
  const normalizedSymbolAdjustments = Object.fromEntries(
    Object.entries(policy.symbolAdjustments || {})
      .map(([symbol, value]) => [String(symbol || '').trim().toUpperCase(), { ...value }])
      .filter(([symbol]) => Boolean(symbol)),
  );
  return {
    classification: policy.classification,
    trigger: policy.trigger
      ? {
        minTriggerHits: Math.max(1, Math.round(Number(policy.trigger.minTriggerHits) || 1)),
        minStress: clamp(Number(policy.trigger.minStress) || 0, 0, 1),
        requireDirectionalTerms: Array.isArray(policy.trigger.requireDirectionalTerms)
          ? policy.trigger.requireDirectionalTerms.map((item) => String(item || '').trim().toLowerCase()).filter(Boolean).slice(0, 12)
          : [],
      }
      : undefined,
    assets: policy.assets
      ? {
        maxPrimaryAssets: Math.max(0, Math.round(Number(policy.assets.maxPrimaryAssets) || 0)) || undefined,
        maxConfirmAssets: Math.max(0, Math.round(Number(policy.assets.maxConfirmAssets) || 0)) || undefined,
        maxHedgeAssets: Math.max(0, Math.round(Number(policy.assets.maxHedgeAssets) || 0)) || undefined,
      }
      : undefined,
    admission: policy.admission
      ? {
        rejectHitProbability: typeof policy.admission.rejectHitProbability === 'number' ? clamp(policy.admission.rejectHitProbability, 0, 1) : undefined,
        watchHitProbability: typeof policy.admission.watchHitProbability === 'number' ? clamp(policy.admission.watchHitProbability, 0, 1) : undefined,
        rejectExpectedReturnPct: typeof policy.admission.rejectExpectedReturnPct === 'number' ? Number(policy.admission.rejectExpectedReturnPct.toFixed(2)) : undefined,
        watchExpectedReturnPct: typeof policy.admission.watchExpectedReturnPct === 'number' ? Number(policy.admission.watchExpectedReturnPct.toFixed(2)) : undefined,
        rejectScore: typeof policy.admission.rejectScore === 'number' ? clamp(policy.admission.rejectScore, 0, 100) : undefined,
        watchScore: typeof policy.admission.watchScore === 'number' ? clamp(policy.admission.watchScore, 0, 100) : undefined,
      }
      : undefined,
    narrative: policy.narrative
      ? {
        enabled: policy.narrative.enabled !== false,
        minAlignmentScore: typeof policy.narrative.minAlignmentScore === 'number' ? clamp(policy.narrative.minAlignmentScore, 0, 100) : undefined,
        weakPenalty: typeof policy.narrative.weakPenalty === 'number' ? clamp(policy.narrative.weakPenalty, 0, 20) : undefined,
        mismatchPenalty: typeof policy.narrative.mismatchPenalty === 'number' ? clamp(policy.narrative.mismatchPenalty, 0, 30) : undefined,
      }
      : undefined,
    symbolAdjustments: Object.keys(normalizedSymbolAdjustments).length > 0 ? normalizedSymbolAdjustments : undefined,
  };
}

function inferThemeClassification(theme: ThemeRule): ThemeClassification {
  const hedgeCount = theme.assets.filter((asset) => asset.role === 'hedge' || asset.direction === 'hedge').length;
  const directionalCount = theme.assets.filter((asset) => asset.direction === 'long' || asset.direction === 'short').length;
  if (hedgeCount >= Math.max(2, directionalCount)) return 'hedge-heavy';
  if (hedgeCount > 0 && directionalCount > 0) return 'mixed';
  return 'directional';
}

export function resolveThemePolicy(theme: ThemeRule): Required<ThemePolicyDefinition> {
  const classification = theme.policy?.classification || inferThemeClassification(theme);
  const normalized = normalizeThemePolicy(theme.policy) || {};
  return {
    classification,
    trigger: {
      minTriggerHits: normalized.trigger?.minTriggerHits ?? (classification === 'hedge-heavy' ? 2 : classification === 'mixed' ? 2 : 1),
      minStress: normalized.trigger?.minStress ?? (classification === 'hedge-heavy' ? 0.3 : classification === 'mixed' ? 0.18 : 0),
      requireDirectionalTerms: normalized.trigger?.requireDirectionalTerms ?? [],
    },
    assets: {
      maxPrimaryAssets: normalized.assets?.maxPrimaryAssets ?? (classification === 'hedge-heavy' ? 1 : classification === 'mixed' ? 2 : 2),
      maxConfirmAssets: normalized.assets?.maxConfirmAssets ?? (classification === 'hedge-heavy' ? 1 : 2),
      maxHedgeAssets: normalized.assets?.maxHedgeAssets ?? (classification === 'directional' ? 1 : 2),
    },
    admission: {
      rejectHitProbability: normalized.admission?.rejectHitProbability ?? (classification === 'hedge-heavy' ? 0.46 : 0.44),
      watchHitProbability: normalized.admission?.watchHitProbability ?? (classification === 'hedge-heavy' ? 0.54 : 0.52),
      rejectExpectedReturnPct: normalized.admission?.rejectExpectedReturnPct ?? (classification === 'hedge-heavy' ? -0.05 : -0.2),
      watchExpectedReturnPct: normalized.admission?.watchExpectedReturnPct ?? (classification === 'hedge-heavy' ? 0.1 : 0.08),
      rejectScore: normalized.admission?.rejectScore ?? (classification === 'hedge-heavy' ? 42 : 38),
      watchScore: normalized.admission?.watchScore ?? (classification === 'hedge-heavy' ? 54 : 52),
    },
    narrative: {
      enabled: normalized.narrative?.enabled ?? classification !== 'directional',
      minAlignmentScore: normalized.narrative?.minAlignmentScore ?? (classification === 'hedge-heavy' ? 48 : 44),
      weakPenalty: normalized.narrative?.weakPenalty ?? 3,
      mismatchPenalty: normalized.narrative?.mismatchPenalty ?? 7,
    },
    symbolAdjustments: {
      ...SPECIAL_SYMBOL_POLICY,
      ...(normalized.symbolAdjustments || {}),
    },
  };
}

function extractThemeLexicon(theme: ThemeRule): string[] {
  const assetAliases = theme.assets.flatMap((asset) => {
    const catalog = UNIVERSE_ASSET_CATALOG.find((entry) => normalize(entry.symbol) === normalize(asset.symbol));
    return catalog?.aliases || [];
  });
  return Array.from(new Set([
    ...theme.triggers,
    ...theme.sectors,
    ...theme.commodities,
    theme.label,
    ...assetAliases,
  ].map((item) => String(item || '').trim().toLowerCase()).filter(Boolean)));
}

function computeNarrativeAlignmentScore(candidate: EventCandidate, theme: ThemeRule, triggerHits: string[]): number {
  const text = normalize(String(candidate.text || ''));
  const lexicon = extractThemeLexicon(theme);
  if (!text || !lexicon.length) return triggerHits.length > 0 ? 55 : 0;
  const directionalTerms = resolveThemePolicy(theme).trigger.requireDirectionalTerms || [];
  const lexiconHits = lexicon.filter((term) => matchesThemeTrigger(text, term));
  const directionalHits = directionalTerms.filter((term) => matchesThemeTrigger(text, term));
  const symbolHits = candidate.matchedSymbols.filter((symbol) => themeHasAssetSymbol(theme, symbol));
  return clamp(
    Math.round(
      18
      + triggerHits.length * 14
      + lexiconHits.length * 5
      + directionalHits.length * 8
      + symbolHits.length * 11
      + candidate.corroborationQuality * 0.18
      + candidate.sourceDiversity * 0.08
      + candidate.marketStress * 14,
    ),
    0,
    100,
  );
}

function classifyNarrativeShadowState(theme: ThemeRule, narrativeAlignmentScore: number): NarrativeShadowState {
  const minAlignment = resolveThemePolicy(theme).narrative.minAlignmentScore || 48;
  if (narrativeAlignmentScore >= minAlignment) return 'aligned';
  if (narrativeAlignmentScore >= minAlignment - 10) return 'weak';
  return 'mismatch';
}

/**
 * Normalizes a theme's arrays (triggers, sectors, commodities, invalidation)
 * and assets, ensuring all values are properly trimmed and validated
 */
export function normalizeThemeDefinition(theme: InvestmentThemeDefinition): InvestmentThemeDefinition {
  return {
    id: String(theme.id || '').trim().toLowerCase(),
    label: String(theme.label || '').trim() || 'Untitled Theme',
    triggers: Array.isArray(theme.triggers) ? theme.triggers.map((item) => String(item || '').trim().toLowerCase()).filter(Boolean).slice(0, 20) : [],
    sectors: Array.isArray(theme.sectors) ? theme.sectors.map((item) => String(item || '').trim().toLowerCase()).filter(Boolean).slice(0, 10) : [],
    commodities: Array.isArray(theme.commodities) ? theme.commodities.map((item) => String(item || '').trim().toLowerCase()).filter(Boolean).slice(0, 10) : [],
    timeframe: String(theme.timeframe || '1d-7d').trim() || '1d-7d',
    thesis: String(theme.thesis || 'Automated theme proposal.').trim() || 'Automated theme proposal.',
    invalidation: Array.isArray(theme.invalidation) ? theme.invalidation.map((item) => String(item || '').trim()).filter(Boolean).slice(0, 6) : [],
    baseSensitivity: clamp(Number(theme.baseSensitivity) || 60, 25, 95),
    policy: normalizeThemePolicy(theme.policy),
    assets: dedupeThemeAssets(
      Array.isArray(theme.assets)
        ? theme.assets
          .map((asset) => ({
            symbol: String(asset.symbol || '').trim().toUpperCase(),
            name: String(asset.name || asset.symbol || '').trim() || String(asset.symbol || '').trim().toUpperCase(),
            assetKind: asset.assetKind,
            sector: String(asset.sector || 'cross-asset').trim().toLowerCase() || 'cross-asset',
            commodity: asset.commodity ? String(asset.commodity).trim().toLowerCase() : undefined,
            direction: asset.direction,
            role: asset.role,
          }))
          .filter((asset) => asset.symbol && asset.assetKind && asset.direction && asset.role)
        : [],
    ),
  };
}

/**
 * Returns the effective theme catalog: base THEME_RULES plus any automated themes
 */
export function listEffectiveThemeCatalog(): ThemeRule[] {
  return [
    ...THEME_RULES,
    ...Array.from(automatedThemes.values()).map((theme) => normalizeThemeDefinition(theme)),
  ];
}

/**
 * Returns a deep copy of the base investment themes (THEME_RULES)
 */
export function listBaseInvestmentThemes(): InvestmentThemeDefinition[] {
  return THEME_RULES.map((theme) => ({
    ...theme,
    triggers: theme.triggers.slice(),
    sectors: theme.sectors.slice(),
    commodities: theme.commodities.slice(),
    invalidation: theme.invalidation.slice(),
    assets: theme.assets.map((asset) => ({ ...asset })),
  }));
}

/**
 * Returns a deep copy of the automated investment themes
 */
export function listAutomatedInvestmentThemes(): InvestmentThemeDefinition[] {
  return Array.from(automatedThemes.values()).map((theme) => ({
    ...theme,
    triggers: theme.triggers.slice(),
    sectors: theme.sectors.slice(),
    commodities: theme.commodities.slice(),
    invalidation: theme.invalidation.slice(),
    assets: theme.assets.map((asset) => ({ ...asset })),
  }));
}

/**
 * Sets the automated theme catalog to the provided themes,
 * normalizing each one and filtering out invalid entries
 */
export function setAutomatedThemeCatalog(themes: InvestmentThemeDefinition[]): void {
  setAutomatedThemes(
    new Map(
      (themes || [])
        .map((theme) => normalizeThemeDefinition(theme))
        .filter((theme) => theme.id && theme.triggers.length > 0)
        .map((theme) => [theme.id, theme] as const),
    ),
  );
}

export function buildThemeMatchDetails(candidate: EventCandidate): ThemeMatchDetail[] {
  const themeCatalog = listEffectiveThemeCatalog();
  const shadowScores = scoreNarrativeShadowThemes(candidate, themeCatalog);
  const shadowByThemeId = new Map(shadowScores.map((row) => [row.themeId, row]));
  const topShadowTheme = shadowScores[0] || null;
  const directMatches: ThemeMatchDetail[] = [];
  const fallbackMatches: ThemeMatchDetail[] = [];
  const normalizedText = normalize(String(candidate.text || ''));

  for (const theme of themeCatalog) {
    const policy = resolveThemePolicy(theme);
    const requiredDirectionalTerms = policy.trigger.requireDirectionalTerms || [];
    const minTriggerHits = policy.trigger.minTriggerHits || 1;
    const minStress = policy.trigger.minStress || 0;
    const triggerHits = theme.triggers.filter((trigger) => matchesThemeTrigger(normalizedText, trigger));
    const directionalHits = requiredDirectionalTerms.filter((term) => matchesThemeTrigger(normalizedText, term));
    const narrativeAlignmentScore = computeNarrativeAlignmentScore(candidate, theme, triggerHits);
    const narrativeShadowState = classifyNarrativeShadowState(theme, narrativeAlignmentScore);
    const shadow = shadowByThemeId.get(theme.id);
    const narrativeShadowPosterior = shadow?.posterior ?? 0;
    const narrativeShadowDisagreement = topShadowTheme && topShadowTheme.themeId !== theme.id
      ? clamp(Number(((topShadowTheme.posterior - narrativeShadowPosterior) * 100).toFixed(2)), 0, 100)
      : 0;
    const triggerPass =
      triggerHits.length >= minTriggerHits
      && candidate.marketStress >= minStress
      && (requiredDirectionalTerms.length === 0 || directionalHits.length > 0);
    const fallbackSymbolHits = candidate.matchedSymbols.filter((symbol) => themeHasAssetSymbol(theme, symbol));
    const fallbackPass =
      !triggerPass
      && fallbackSymbolHits.length > 0
      && candidate.marketStress >= Math.max(minStress, 0.55);
    if (!triggerPass && !fallbackPass) continue;
    const score = Number((
      triggerHits.length * 16
      + fallbackSymbolHits.length * 10
      + narrativeAlignmentScore * 0.42
      + candidate.corroborationQuality * 0.12
      + candidate.eventIntensity * 0.08
      + candidate.aftershockIntensity * 10
      - (narrativeShadowState === 'mismatch' ? 8 : narrativeShadowState === 'weak' ? 3 : 0)
    ).toFixed(2));
    const detail: ThemeMatchDetail = {
      theme,
      triggerHits,
      triggerHitCount: triggerHits.length,
      narrativeAlignmentScore,
      narrativeShadowState,
      narrativeShadowPosterior,
      narrativeShadowDisagreement,
      narrativeShadowTopThemeId: topShadowTheme?.themeId ?? null,
      score,
      matchedBy: triggerPass ? 'trigger' : 'fallback-symbol',
    };
    if (triggerPass) {
      directMatches.push(detail);
    } else {
      fallbackMatches.push(detail);
    }
  }

  const ranked = (directMatches.length > 0 ? directMatches : fallbackMatches)
    .sort((left, right) => right.score - left.score || right.triggerHitCount - left.triggerHitCount)
    .slice(0, candidate.marketStress >= 0.65 ? 4 : 3);
  return ranked;
}

/**
 * Finds themes that match an EventCandidate by trigger matching,
 * and falls back to symbol matching if market stress is high
 */
export function findMatchingThemes(candidate: EventCandidate): ThemeRule[] {
  return buildThemeMatchDetails(candidate).map((match) => match.theme);
}

/**
 * Finds a theme rule by its id from the effective catalog
 */
export function getThemeRule(themeId: string): ThemeRule | null {
  return listEffectiveThemeCatalog().find((theme) => theme.id === themeId) || null;
}

/**
 * Gets the effective theme assets including both base assets and accepted candidate reviews
 */
export function getEffectiveThemeAssets(theme: ThemeRule): ThemeAssetDefinition[] {
  const accepted = Array.from(candidateReviews.values())
    .filter((review) => review.themeId === theme.id && review.status === 'accepted')
    .map(reviewToThemeAsset);
  return dedupeThemeAssets([...theme.assets, ...accepted]);
}

export function selectThemeAssetsForCandidate(
  theme: ThemeRule,
  candidate: EventCandidate,
  matchDetail?: ThemeMatchDetail | null,
): ThemeAssetDefinition[] {
  const policy = resolveThemePolicy(theme);
  const symbolAdjustments = policy.symbolAdjustments;
  const maxPrimaryAssets = policy.assets.maxPrimaryAssets || 2;
  const maxConfirmAssets = policy.assets.maxConfirmAssets || 2;
  const maxHedgeAssets = policy.assets.maxHedgeAssets || 1;
  const assets = getEffectiveThemeAssets(theme)
    .filter((asset) => {
      const symbolRule = symbolAdjustments[String(asset.symbol || '').trim().toUpperCase()];
      if (!symbolRule?.requireRiskOff) return true;
      return candidate.marketStress >= 0.45;
    });
  const ranked = assets.slice().sort((left, right) => {
    const leftCatalog = UNIVERSE_ASSET_CATALOG.find((entry) => normalize(entry.symbol) === normalize(left.symbol));
    const rightCatalog = UNIVERSE_ASSET_CATALOG.find((entry) => normalize(entry.symbol) === normalize(right.symbol));
    const leftLiquidity = leftCatalog?.liquidityTier === 'high' ? 3 : leftCatalog?.liquidityTier === 'medium' ? 2 : 1;
    const rightLiquidity = rightCatalog?.liquidityTier === 'high' ? 3 : rightCatalog?.liquidityTier === 'medium' ? 2 : 1;
    const leftRole = left.role === 'primary' ? 3 : left.role === 'confirm' ? 2 : 1;
    const rightRole = right.role === 'primary' ? 3 : right.role === 'confirm' ? 2 : 1;
    return rightRole - leftRole || rightLiquidity - leftLiquidity;
  });
  const picked: ThemeAssetDefinition[] = [];
  let primaryCount = 0;
  let confirmCount = 0;
  let hedgeCount = 0;
  for (const asset of ranked) {
    const nextPrimary = asset.role === 'primary' ? primaryCount + 1 : primaryCount;
    const nextConfirm = asset.role === 'confirm' ? confirmCount + 1 : confirmCount;
    const nextHedge = asset.role === 'hedge' ? hedgeCount + 1 : hedgeCount;
    if (nextPrimary > maxPrimaryAssets) continue;
    if (nextConfirm > maxConfirmAssets) continue;
    if (nextHedge > maxHedgeAssets) continue;
    if (
      policy.classification === 'hedge-heavy'
      && matchDetail?.narrativeShadowState === 'mismatch'
      && asset.role === 'hedge'
      && hedgeCount > 0
    ) {
      continue;
    }
    picked.push(asset);
    primaryCount = nextPrimary;
    confirmCount = nextConfirm;
    hedgeCount = nextHedge;
  }
  return picked.length > 0 ? picked : ranked.slice(0, 2);
}

/**
 * Checks if a theme has a specific asset symbol (including accepted candidates)
 */
export function themeHasAssetSymbol(theme: ThemeRule, symbol: string): boolean {
  const normalizedSymbol = normalize(symbol);
  return getEffectiveThemeAssets(theme).some((asset) => normalize(asset.symbol) === normalizedSymbol);
}

/**
 * Builds a lookup map from normalized symbols to watchlist entries
 */
export function buildWatchlistLookup(): Map<string, { symbol: string; name?: string }> {
  const lookup = new Map<string, { symbol: string; name?: string }>();
  for (const entry of getMarketWatchlistEntries()) {
    lookup.set(normalize(entry.symbol), { symbol: entry.symbol, name: entry.name });
  }
  return lookup;
}

/**
 * Auto-promote discovered patterns to themes.
 * Called periodically to check if any discovered patterns qualify as themes.
 */
export function promoteDiscoveredPatternsToThemes(): InvestmentThemeDefinition[] {
  const patterns = getSignificantPatterns(5, 1.5); // At least 5 samples, t-stat >= 1.5
  const promoted: InvestmentThemeDefinition[] = [];
  const existingIds = new Set(listEffectiveThemeCatalog().map(t => t.id));

  // Group patterns by fingerprint (same news type -> same theme)
  const byFingerprint = new Map<string, DiscoveredLink[]>();
  for (const p of patterns) {
    const existing = byFingerprint.get(p.clusterFingerprint) || [];
    existing.push(p);
    byFingerprint.set(p.clusterFingerprint, existing);
  }

  for (const [fpId, links] of byFingerprint) {
    const themeId = `discovered-${fpId}`;
    if (existingIds.has(themeId)) continue;
    if (links.length < 2) continue; // Need at least 2 symbol connections

    // Build theme from discovered links
    const assets: ThemeAssetDefinition[] = links.slice(0, 6).map(link => ({
      symbol: link.symbol,
      name: link.symbol,
      assetKind: 'etf' as const,
      sector: 'discovered',
      commodity: undefined,
      direction: link.direction as 'long' | 'short',
      role: (link.tStat > 2 ? 'primary' : 'confirm') as 'primary' | 'confirm' | 'hedge',
    }));

    // Best horizon across all links
    const bestLink = links.reduce((a, b) => Math.abs(a.tStat) > Math.abs(b.tStat) ? a : b);
    const timeframe = `${Math.max(1, Math.floor(bestLink.horizonHours / 24))}d-${Math.ceil(bestLink.horizonHours / 24) * 2}d`;

    // Extract triggers from fingerprint
    const triggers = fpId.split('-').filter(t => t.length > 2);

    promoted.push({
      id: themeId,
      label: `Discovered: ${fpId}`,
      triggers,
      sectors: ['discovered'],
      commodities: [],
      timeframe,
      thesis: `Auto-discovered pattern: ${fpId} correlates with ${links.map(l => l.symbol).join(', ')} at ${bestLink.horizonHours}h horizon (t=${bestLink.tStat.toFixed(1)}, n=${bestLink.sampleCount})`,
      invalidation: ['Pattern breaks down', 'Correlation becomes insignificant'],
      baseSensitivity: clamp(Math.round(50 + bestLink.tStat * 5), 25, 80),
      assets,
    });
  }

  // Register promoted themes
  if (promoted.length > 0) {
    const existingAutomated = Array.from(automatedThemes.values()).filter(t => t.id.startsWith('discovered-'));
    // Keep max 10 discovered themes, remove oldest if needed
    const combined = [...existingAutomated, ...promoted].slice(-10);
    // Preserve non-discovered automated themes and add discovered ones
    const nonDiscovered = Array.from(automatedThemes.values()).filter(t => !t.id.startsWith('discovered-'));
    setAutomatedThemeCatalog([...nonDiscovered, ...combined]);
  }

  return promoted;
}

/**
 * User-customizable market watchlist (additive).
 *
 * Stores a list of extra tickers the user wants to track beyond the defaults.
 * Optional friendly label is supported (used as the displayed name).
 */

export interface MarketWatchlistEntry {
  symbol: string;
  /** Friendly label shown in the UI (maps to MarketData.name). */
  name?: string;
  /** Optional short display code (maps to MarketData.display). Defaults to symbol. */
  display?: string;
}

const STORAGE_KEY = 'wm-market-watchlist-v1';
export const MARKET_WATCHLIST_EVENT = 'wm-market-watchlist-changed';

function safeParseJson<T>(raw: string | null): T | null {
  if (!raw) return null;
  try { return JSON.parse(raw) as T; } catch { return null; }
}

function normalizeSymbol(raw: string): string {
  // Allow common finnhub/yahoo formats: ^GSPC, BRK-B, GC=F, BTCUSD, etc.
  // Only trim whitespace and remove internal spaces.
  return raw.trim().replace(/\s+/g, '');
}

function normalizeName(raw: string | undefined): string | undefined {
  const v = (raw || '').trim();
  return v ? v : undefined;
}

function coerceEntry(v: unknown): MarketWatchlistEntry | null {
  if (typeof v === 'string') {
    const sym = normalizeSymbol(v);
    if (!sym) return null;
    return { symbol: sym };
  }
  if (v && typeof v === 'object') {
    const obj = v as any;
    const sym = normalizeSymbol(String(obj.symbol || ''));
    if (!sym) return null;
    const name = normalizeName(typeof obj.name === 'string' ? obj.name : undefined);
    const display = normalizeName(typeof obj.display === 'string' ? obj.display : undefined);
    return { symbol: sym, ...(name ? { name } : {}), ...(display ? { display } : {}) };
  }
  return null;
}

export function getMarketWatchlistEntries(): MarketWatchlistEntry[] {
  try {
    const parsed = safeParseJson<unknown>(localStorage.getItem(STORAGE_KEY));
    if (Array.isArray(parsed)) {
      const entries: MarketWatchlistEntry[] = [];
      for (const item of parsed) {
        const e = coerceEntry(item);
        if (e) entries.push(e);
      }
      return entries;
    }
  } catch {
    // ignore
  }
  return [];
}

export function setMarketWatchlistEntries(entries: MarketWatchlistEntry[]): void {
  // Clean, de-dupe by symbol but keep order.
  const seen = new Set<string>();
  const out: MarketWatchlistEntry[] = [];

  for (const raw of entries || []) {
    const sym = normalizeSymbol(raw.symbol || '');
    if (!sym || seen.has(sym)) continue;
    seen.add(sym);

    const name = normalizeName(raw.name);
    const display = normalizeName(raw.display);

    out.push({ symbol: sym, ...(name ? { name } : {}), ...(display ? { display } : {}) });
    if (out.length >= 50) break;
  }

  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(out));
  } catch {
    // ignore
  }

  window.dispatchEvent(new CustomEvent(MARKET_WATCHLIST_EVENT, { detail: { entries: out } }));
}

export function resetMarketWatchlist(): void {
  try { localStorage.removeItem(STORAGE_KEY); } catch { /* ignore */ }
  window.dispatchEvent(new CustomEvent(MARKET_WATCHLIST_EVENT, { detail: { entries: [] } }));
}

export function subscribeMarketWatchlistChange(cb: (entries: MarketWatchlistEntry[]) => void): () => void {
  const handler = (e: Event) => {
    const detail = (e as CustomEvent).detail as { entries?: unknown } | undefined;
    if (Array.isArray(detail?.entries)) {
      const coerced: MarketWatchlistEntry[] = [];
      for (const it of detail!.entries!) {
        const ce = coerceEntry(it);
        if (ce) coerced.push(ce);
      }
      cb(coerced);
      return;
    }
    cb(getMarketWatchlistEntries());
  };
  window.addEventListener(MARKET_WATCHLIST_EVENT, handler);
  return () => window.removeEventListener(MARKET_WATCHLIST_EVENT, handler);
}

export function parseMarketWatchlistInput(text: string): MarketWatchlistEntry[] {
  // Accept comma or newline-separated entries.
  // Friendly label format: SYMBOL|Label (ex: TSLA|Tesla)
  const rawItems = text
    .split(/[\n,]+/g)
    .map((s) => s.trim())
    .filter(Boolean);

  const entries: MarketWatchlistEntry[] = [];

  for (const item of rawItems) {
    const [left, ...rest] = item.split('|');
    const symbol = normalizeSymbol(left || '');
    if (!symbol) continue;
    const name = normalizeName(rest.join('|'));
    entries.push({ symbol, ...(name ? { name } : {}) });
  }

  return entries;
}

import { getSignificantPatterns } from '../pattern-discovery';
import type { EventCandidate, InvestmentThemeDefinition, NarrativeFactorShadowThemeScore } from './types';
import { UNIVERSE_ASSET_CATALOG } from './constants';
import { clamp, matchesThemeTrigger, normalize } from './utils';

const TOKEN_STOPWORDS = new Set([
  'the', 'and', 'for', 'with', 'from', 'amid', 'after', 'over', 'near', 'about', 'against',
  'this', 'that', 'have', 'more', 'than', 'their', 'its', 'into', 'under', 'while', 'when',
  'will', 'said', 'says', 'report', 'reports', 'breaking', 'latest', 'update', 'updates',
]);

function tokenize(value: string): string[] {
  return Array.from(
    new Set(
      normalize(value)
        .split(/[^a-z0-9-]+/g)
        .filter((token) => token.length >= 3 && !TOKEN_STOPWORDS.has(token)),
    ),
  ).slice(0, 64);
}

function overlapCount(left: Iterable<string>, right: Iterable<string>): number {
  const rightSet = right instanceof Set ? right : new Set(right);
  let count = 0;
  for (const token of left) {
    if (rightSet.has(token)) count += 1;
  }
  return count;
}

function themeLexicon(theme: InvestmentThemeDefinition): Set<string> {
  const assetAliases = theme.assets.flatMap((asset) => {
    const catalog = UNIVERSE_ASSET_CATALOG.find((entry) => normalize(entry.symbol) === normalize(asset.symbol));
    return [asset.symbol, asset.name, ...(catalog?.aliases || [])];
  });
  return new Set([
    ...theme.triggers,
    ...theme.sectors,
    ...theme.commodities,
    theme.label,
    theme.thesis,
    ...assetAliases,
  ].flatMap((entry) => tokenize(String(entry || ''))));
}

function softmax(values: number[]): number[] {
  if (values.length === 0) return [];
  const max = Math.max(...values);
  const exps = values.map((value) => Math.exp(value - max));
  const total = exps.reduce((sum, value) => sum + value, 0);
  return exps.map((value) => value / Math.max(total, 1e-9));
}

export function scoreNarrativeShadowThemes(
  candidate: EventCandidate,
  themeCatalog: InvestmentThemeDefinition[],
): NarrativeFactorShadowThemeScore[] {
  const candidateTerms = new Set([
    ...tokenize(candidate.text || ''),
    ...candidate.graphTerms.flatMap((term) => tokenize(String(term || ''))),
    ...candidate.matchedSymbols.map((symbol) => normalize(symbol)),
  ]);
  const patterns = getSignificantPatterns(2, 0.8);
  const rawRows = themeCatalog.map((theme) => {
    const lexicon = themeLexicon(theme);
    const lexiconHitCount = overlapCount(candidateTerms, lexicon);
    const directPhraseHits = theme.triggers.filter((trigger) => matchesThemeTrigger(candidate.text || '', trigger)).length;
    const symbolOverlapCount = candidate.matchedSymbols.filter((symbol) => theme.assets.some((asset) => normalize(asset.symbol) === normalize(symbol))).length;
    const themeAssetSet = new Set(theme.assets.map((asset) => normalize(asset.symbol)));
    const patternMatches = patterns.filter((pattern) => {
      if (!themeAssetSet.has(normalize(pattern.symbol))) return false;
      const fpTerms = String(pattern.clusterFingerprint || '').split('-').map((term) => normalize(term)).filter(Boolean);
      return overlapCount(candidateTerms, fpTerms) > 0;
    });
    const patternSupportScore = Number(patternMatches.reduce((sum, pattern) => (
      sum
      + Math.min(2.5, Math.abs(pattern.tStat) / 2.2)
      + Math.min(1.8, pattern.sampleCount / 6)
      + Math.min(1.5, Math.abs(pattern.avgReturnPct) / 0.8)
    ), 0).toFixed(2));
    const alignmentScore = clamp(Math.round(
      16
      + directPhraseHits * 14
      + lexiconHitCount * 7
      + symbolOverlapCount * 12
      + patternSupportScore * 7
      + candidate.corroborationQuality * 0.1
      + candidate.marketStress * 10
      + candidate.eventIntensity * 0.06,
    ), 0, 100);
    const rawScore = Number((
      directPhraseHits * 1.4
      + lexiconHitCount * 0.75
      + symbolOverlapCount * 1.2
      + patternSupportScore * 0.9
      + candidate.marketStress * 0.35
      + candidate.aftershockIntensity * 0.18
    ).toFixed(4));
    return {
      themeId: theme.id,
      themeLabel: theme.label,
      rawScore,
      posterior: 0,
      alignmentScore,
      patternSupportScore: Number(patternSupportScore.toFixed(2)),
      lexiconHitCount: directPhraseHits + lexiconHitCount,
      symbolOverlapCount,
      evidence: [
        directPhraseHits > 0 ? `triggerHits=${directPhraseHits}` : '',
        lexiconHitCount > 0 ? `tokenHits=${lexiconHitCount}` : '',
        symbolOverlapCount > 0 ? `symbolHits=${symbolOverlapCount}` : '',
        patternSupportScore > 0 ? `patternSupport=${patternSupportScore.toFixed(1)}` : '',
      ].filter(Boolean),
    };
  });
  const posteriors = softmax(rawRows.map((row) => row.rawScore));
  return rawRows
    .map((row, index) => ({ ...row, posterior: Number(posteriors[index]!.toFixed(6)) }))
    .sort((left, right) => right.posterior - left.posterior || right.alignmentScore - left.alignmentScore);
}

export interface AttributionComponent {
  key: string;
  label: string;
  contribution: number;
  explanation: string;
}

export interface IdeaAttributionBreakdown {
  primaryDriver: string;
  primaryPenalty: string;
  components: AttributionComponent[];
  narrative: string;
  failureModes: string[];
}

function round(value: number): number {
  return Number(value.toFixed(2));
}

function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, value));
}

function sortComponents(components: AttributionComponent[]): AttributionComponent[] {
  return components.slice().sort((a, b) => Math.abs(b.contribution) - Math.abs(a.contribution));
}

export function buildIdeaAttribution(args: {
  themeLabel: string;
  symbol: string;
  corroborationQuality: number;
  contradictionPenalty: number;
  recentEvidenceScore: number;
  stalePenalty: number;
  realityScore: number;
  transferEntropy: number;
  banditScore: number;
  graphSignalScore: number;
  regimeMultiplier: number;
  macroPenalty: number;
  falsePositiveRisk: number;
  marketMovePct: number | null;
}): IdeaAttributionBreakdown {
  const corroboration = clamp(args.corroborationQuality / 100, 0, 1);
  const recentEvidence = clamp(args.recentEvidenceScore / 100, 0, 1);
  const reality = clamp(args.realityScore / 100, 0, 1);
  const graph = clamp(args.graphSignalScore / 100, 0, 1);
  const transferEntropy = clamp(args.transferEntropy, 0, 1);
  const bandit = clamp((args.banditScore + 1.5) / 3, 0, 1);
  const regime = clamp((args.regimeMultiplier - 1) / 0.5, -1, 1);
  const contradiction = clamp(args.contradictionPenalty / 30, 0, 1);
  const falsePositive = clamp(args.falsePositiveRisk / 100, 0, 1);
  const components: AttributionComponent[] = [
    {
      key: 'corroboration',
      label: 'Cross-source corroboration',
      contribution: round((corroboration - 0.5) * 22),
      explanation: 'Measures whether multiple sources agree on the event with sufficient diversity.',
    },
    {
      key: 'recentEvidence',
      label: 'Recent evidence',
      contribution: round((recentEvidence - 0.5) * 16 - args.stalePenalty * 0.25),
      explanation: 'Rewards fresh realized samples and penalizes stale priors.',
    },
    {
      key: 'reality',
      label: 'Execution reality',
      contribution: round((reality - 0.5) * 18),
      explanation: 'Rewards liquid, tradable setups and penalizes spread/slippage friction.',
    },
    {
      key: 'regime',
      label: 'Macro regime fit',
      contribution: round(regime * 14 - args.macroPenalty * 0.35),
      explanation: 'Measures whether the idea fits the active top-down market regime and kill-switch state.',
    },
    {
      key: 'graph',
      label: 'Graph propagation',
      contribution: round((graph - 0.5) * 14),
      explanation: 'Rewards multi-hop propagation support across entities, sectors, and transmission edges.',
    },
    {
      key: 'learning',
      label: 'Adaptive learning',
      contribution: round((transferEntropy - 0.4) * 10 + (bandit - 0.5) * 10),
      explanation: 'Combines transmission lead-lag structure with bandit exploration/exploitation confidence.',
    },
    {
      key: 'contradiction',
      label: 'Contradiction penalty',
      contribution: round(-(contradiction * 16 + falsePositive * 12)),
      explanation: 'Penalizes conflicting headlines, rumor language, and false-positive risk.',
    },
    {
      key: 'beta',
      label: 'Market beta drift',
      contribution: round((args.marketMovePct || 0) * 0.65),
      explanation: 'Captures whether the asset is already moving with or against the proposed thesis.',
    },
  ];

  const sorted = sortComponents(components);
  const primaryDriver = sorted.find((component) => component.contribution > 0)?.label || 'No positive driver dominated';
  const primaryPenalty = sorted.slice().reverse().find((component) => component.contribution < 0)?.label || 'No major penalty dominated';
  const positiveDrivers = sorted.filter((component) => component.contribution > 0).slice(0, 2).map((component) => component.label.toLowerCase());
  const negativeDrivers = sorted.filter((component) => component.contribution < 0).slice(0, 2).map((component) => component.label.toLowerCase());
  const failureModes = [
    args.falsePositiveRisk >= 40 ? 'False-positive risk is still elevated.' : '',
    args.realityScore < 45 ? 'Execution frictions can erase most of the raw edge.' : '',
    args.recentEvidenceScore < 36 ? 'Recent evidence is too thin for confident live deployment.' : '',
    args.contradictionPenalty >= 12 ? 'Contradictory reporting remains unresolved.' : '',
    args.macroPenalty >= 12 ? 'Top-down macro overlay is actively suppressing this idea.' : '',
  ].filter(Boolean);

  return {
    primaryDriver,
    primaryPenalty,
    components: sorted,
    narrative: `${args.themeLabel} / ${args.symbol} leans on ${positiveDrivers.join(' and ') || 'limited support'}, while ${negativeDrivers.join(' and ') || 'few penalties'} is holding confidence back.`,
    failureModes,
  };
}

import type { ClusteredEvent, MarketData } from '@/types';
import type { MarketRegimeState } from './math-models/regime-model';
import type { SelfTuningWeightProfile } from './experiment-registry';

export type MacroRiskState = 'risk-on' | 'balanced' | 'risk-off' | 'crash';

export interface MacroRiskDriver {
  label: string;
  value: number;
  tone: 'positive' | 'negative' | 'neutral';
}

export interface MacroHedgeSuggestion {
  symbol: string;
  weightPct: number;
  reason: string;
}

export interface MacroRiskOverlay {
  generatedAt: string;
  state: MacroRiskState;
  riskGauge: number;
  netExposureCapPct: number;
  grossExposureCapPct: number;
  killSwitch: boolean;
  topDownAction: 'normal' | 'trim' | 'defend' | 'kill-switch';
  hedgeBias: MacroHedgeSuggestion[];
  drivers: MacroRiskDriver[];
  notes: string[];
}

function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, value));
}

function marketChange(markets: MarketData[], symbols: string[]): number {
  const rows = markets
    .filter((market) => symbols.includes(String(market.symbol || '')))
    .map((market) => Number(market.change))
    .filter((value) => Number.isFinite(value));
  if (!rows.length) return 0;
  return rows.reduce((sum, value) => sum + value, 0) / rows.length;
}

function average(values: number[]): number {
  if (!values.length) return 0;
  return values.reduce((sum, value) => sum + value, 0) / values.length;
}

export function buildMacroRiskOverlay(args: {
  regime: MarketRegimeState | null | undefined;
  markets: MarketData[];
  clusters?: ClusteredEvent[];
  weightProfile?: SelfTuningWeightProfile | null;
}): MacroRiskOverlay {
  const regime = args.regime ?? null;
  const weightProfile = args.weightProfile ?? null;
  const vixChange = marketChange(args.markets, ['^VIX']);
  const equityChange = marketChange(args.markets, ['^GSPC', '^DJI']);
  const techChange = marketChange(args.markets, ['^IXIC', 'XLK', 'NVDA']);
  const ratesHedgeChange = marketChange(args.markets, ['TLT', 'SHY', 'GOVT']);
  const goldChange = marketChange(args.markets, ['GLD', 'IAU', 'GC=F']);
  const dollarChange = marketChange(args.markets, ['UUP', 'DX-Y.NYB']);
  const flashSignals = average((args.clusters || []).slice(0, 12).map((cluster) => Number(cluster.sourceCount || 0) + (cluster.isAlert ? 2 : 0)));

  const regimeBase = regime?.id === 'deflation-bust'
    ? 72
    : regime?.id === 'risk-off'
      ? 64
      : regime?.id === 'inflation-shock'
        ? 56
        : 32;
  const regimeConfidenceAdj = (regime?.confidence || 0) * 0.22;
  const vixStress = Math.max(0, vixChange) * 4.6;
  const equityStress = Math.max(0, -equityChange) * 4.3;
  const techStress = Math.max(0, -techChange) * 3.7;
  const hedgeBid = Math.max(0, ratesHedgeChange) * 2 + Math.max(0, goldChange) * 2 + Math.max(0, dollarChange) * 1.8;
  const warStress = (regime?.features.warIntensity || 0) * 0.18;
  const inflationStress = (regime?.features.inflationPressure || 0) * 0.16;
  const growthStress = (regime?.features.growthStress || 0) * 0.2;
  const policyStress = (regime?.features.policyStress || 0) * 0.14;
  const profileAdj = (weightProfile?.riskOffExposureMultiplier || 1) * 6.5 - 6.5;
  const flashStress = Math.min(10, flashSignals * 1.2);

  const riskGauge = clamp(Math.round(
    regimeBase
    + regimeConfidenceAdj
    + vixStress
    + equityStress
    + techStress
    + hedgeBid
    + warStress
    + inflationStress
    + growthStress
    + policyStress
    + flashStress
    + profileAdj
    - (regime?.id === 'risk-on' ? Math.max(0, techChange) * 3.5 : 0)
  ), 4, 100);

  const state: MacroRiskState = riskGauge >= 82
    ? 'crash'
    : riskGauge >= 66
      ? 'risk-off'
      : riskGauge <= 28
        ? 'risk-on'
        : 'balanced';
  const killSwitch = state === 'crash'
    || (state === 'risk-off' && (regime?.confidence || 0) >= 86 && vixChange >= 4.5);

  const baseNetCap = killSwitch
    ? 18
    : state === 'risk-off'
      ? 42
      : state === 'balanced'
        ? 68
        : 100;
  const baseGrossCap = killSwitch
    ? 40
    : state === 'risk-off'
      ? 78
      : state === 'balanced'
        ? 110
        : 145;

  const exposureAdj = clamp((weightProfile?.riskOffExposureMultiplier || 1), 0.6, 1.6);
  const netExposureCapPct = clamp(Math.round(baseNetCap / exposureAdj), 10, 120);
  const grossExposureCapPct = clamp(Math.round(baseGrossCap / Math.max(0.82, exposureAdj * 0.92)), 30, 180);

  const hedgeBias: MacroHedgeSuggestion[] = state === 'risk-on'
    ? []
    : [
      { symbol: 'GLD', weightPct: killSwitch ? 5 : 3, reason: 'Gold absorbs risk-off and escalation stress.' },
      { symbol: 'TLT', weightPct: killSwitch ? 6 : 4, reason: 'Long-duration Treasuries provide macro shock ballast.' },
      { symbol: 'UUP', weightPct: state === 'crash' ? 3 : 2, reason: 'Dollar strength typically accompanies funding stress.' },
      { symbol: '^VIX', weightPct: killSwitch ? 2 : 1, reason: 'Volatility hedges offset abrupt beta compression.' },
    ];

  const notes = [
    killSwitch
      ? 'Macro kill switch is active; new net exposure should collapse toward hedge-only posture.'
      : state === 'risk-off'
        ? 'Top-down risk-off posture is active; new gross exposure should be trimmed and hedges favored.'
        : state === 'balanced'
          ? 'Macro regime is mixed; selective deployment is allowed but net exposure is capped.'
          : 'Macro regime permits normal deployment if idea-level evidence is strong.',
    regime ? `Regime ${regime.label} at ${regime.confidence}% confidence is feeding the overlay.` : 'Regime feed is missing, so the overlay is market-data only.',
  ];

  return {
    generatedAt: new Date().toISOString(),
    state,
    riskGauge,
    netExposureCapPct,
    grossExposureCapPct,
    killSwitch,
    topDownAction: killSwitch ? 'kill-switch' : state === 'risk-off' ? 'defend' : state === 'balanced' ? 'trim' : 'normal',
    hedgeBias,
    drivers: [
      { label: 'VIX', value: Number(vixChange.toFixed(2)), tone: vixChange > 0 ? 'negative' : 'positive' },
      { label: 'Equity Beta', value: Number(equityChange.toFixed(2)), tone: equityChange >= 0 ? 'positive' : 'negative' },
      { label: 'Tech Beta', value: Number(techChange.toFixed(2)), tone: techChange >= 0 ? 'positive' : 'negative' },
      { label: 'Rates Hedge', value: Number(ratesHedgeChange.toFixed(2)), tone: ratesHedgeChange > 0 ? 'negative' : 'neutral' },
      { label: 'Gold', value: Number(goldChange.toFixed(2)), tone: goldChange > 0 ? 'negative' : 'neutral' },
      { label: 'War Stress', value: Number((regime?.features.warIntensity || 0).toFixed(1)), tone: 'negative' },
      { label: 'Growth Stress', value: Number((regime?.features.growthStress || 0).toFixed(1)), tone: 'negative' },
    ],
    notes,
  };
}

